const raw = $input.first().json.data || '{}';
const data = typeof raw === 'string' ? JSON.parse(raw) : raw;
return [{ json: data }];

const token        = $('Obtener Token Ingram').first().json.access_token;
const productos    = $('Parsear Input').first().json.productos || [];
const customerNum  = $vars.INGRAM_CUSTOMER_NUMBER || '';
const countryCode  = $vars.INGRAM_COUNTRY_CODE || 'MX';
const senderId     = $vars.INGRAM_SENDER_ID || 'INTRASIAP';
const isSandbox    = ($vars.INGRAM_SANDBOX || 'true') === 'true';
const baseUrl      = isSandbox
  ? 'https://api.ingrammicro.com:443/sandbox'
  : 'https://api.ingrammicro.com:443';

const correlationId = 'intrasiap-' + Date.now();
const allResults   = [];

for (const producto of productos) {
  try {
    const resp = await $helpers.httpRequest({
      method: 'GET',
      url: `${baseUrl}/resellers/v6/catalog`,
      headers: {
        Authorization:        `Bearer ${token}`,
        'IM-CustomerNumber':  customerNum,
        'IM-CountryCode':     countryCode,
        'IM-CorrelationID':   correlationId,
        'IM-SenderID':        senderId,
        'Content-Type':       'application/json'
      },
      qs: { keyword: producto.searchQuery, pageSize: 5 }
    });

    const items = resp.catalog || resp.products || resp.data || [];
    for (const item of items.slice(0, 3)) {
      allResults.push({
        mayorista:    'Ingram Micro',
        sku:          item.ingramPartNumber || item.vendorPartNumber || '',
        skuFabricante: item.vendorPartNumber || '',
        descripcion:  item.description || item.productDescription || '',
        marca:        item.vendorName || item.brand || producto.marca,
        precio:       Number(item.retailPrice || item.specialPrice || item.price || 0),
        moneda:       'MXN',
        existencia:   Number(item.quantityAvailable || item.availability?.totalAvailability || 0),
        disponible:   (item.quantityAvailable || 0) > 0,
        imagenUrl:    item.thumbnailUrl || item.imagePath || '',
        productoBuscado: producto.searchQuery
      });
    }
  } catch(e) {
    allResults.push({
      mayorista: 'Ingram Micro',
      error: e.message,
      productoBuscado: producto.searchQuery
    });
  }
}

return allResults.map(r => ({ json: r }));

const items = $input.all();
const resultados = items.map(i => i.json).filter(r => !r.error && r.precio > 0);
const errores    = items.map(i => i.json).filter(r => r.error);

return [{
  json: {
    mayorista:  'Ingram Micro',
    exitoso:    resultados.length > 0,
    error:      errores.length > 0 ? errores[0].error : null,
    resultados: resultados,
    timestamp:  new Date().toISOString()
  }
}];
